                  opacity: heroPlaying ? 0.55 : 1,
                  transition: 'opacity 0.5s ease',
                }} />
            )}
            <div>
              <h1 style={{ fontSize: 'clamp(36px,5.5vw,68px)', fontWeight: 900, lineHeight: 0.95, marginBottom: 12, letterSpacing: -1.5, textShadow: '2px 4px 20px rgba(0,0,0,0.9)' }}>
